import { setup, assign } from 'xstate';

interface Player { id: string; ready: boolean }
interface Ctx { players: Player[]; host: string }

type Ev =
  | { type: 'JOIN'; id: string }
  | { type: 'LEAVE'; id: string }
  | { type: 'READY'; id: string }
  | { type: 'UNREADY'; id: string }
  | { type: 'START' }
  | { type: 'CANCEL' }
  | { type: 'LAUNCHED' };

export const lobbyMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  guards: {
    allReady: ({ context }) => context.players.length >= 2 && context.players.every(p => p.ready),
    isHost: ({ context, event }) => event.type === 'START' && context.host === context.players[0]?.id
  }
}).createMachine({
  id: 'lobby',
  context: { players: [], host: '' },
  initial: 'waiting',
  states: {
    waiting: {
      on: {
        JOIN: { actions: assign({ players: ({ context, event }) => [...context.players, { id: event.id, ready: false }], host: ({ context, event }) => context.host || event.id }) },
        LEAVE: { actions: assign({ players: ({ context, event }) => context.players.filter(p => p.id !== event.id) }) },
        READY: { target: 'readyCheck', actions: assign({ players: ({ context, event }) => context.players.map(p => p.id === event.id ? { ...p, ready: true } : p) }) }
      }
    },
    readyCheck: {
      on: {
        READY: { actions: assign({ players: ({ context, event }) => context.players.map(p => p.id === event.id ? { ...p, ready: true } : p) }) },
        UNREADY: { target: 'waiting', actions: assign({ players: ({ context, event }) => context.players.map(p => p.id === event.id ? { ...p, ready: false } : p) }) },
        START: { target: 'starting', guard: 'allReady' }
      }
    },
    starting: {
      after: { 3000: 'inGame' },
      on: { CANCEL: 'readyCheck' }
    },
    inGame: {
      on: { LAUNCHED: 'inGame' }
    }
  }
});
```

