import { setup, assign } from 'xstate';

interface Quote { pair: string; price: number; amount: number }
interface Ctx { quote: Quote | null; txHash: string | null; blockNumber: number }

type Ev =
  | { type: 'QUOTE'; quote: Quote }
  | { type: 'PREVIEW' }
  | { type: 'REJECT' }
  | { type: 'SIGN'; hash: string }
  | { type: 'BROADCAST' }
  | { type: 'CONFIRMED'; block: number };

export const tradeMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actions: {
    storeQuote: assign({ quote: ({ event }) => event.type === 'QUOTE' ? event.quote : null }),
    storeHash: assign({ txHash: ({ event }) => event.type === 'SIGN' ? event.hash : null }),
    storeBlock: assign({ blockNumber: ({ event }) => event.type === 'CONFIRMED' ? event.block : 0 }),
    clear: assign({ quote: () => null, txHash: () => null, blockNumber: () => 0 })
  }
}).createMachine({
  id: 'trade',
  context: { quote: null, txHash: null, blockNumber: 0 },
  initial: 'quote',
  states: {
    quote: { on: { QUOTE: { target: 'previewing', actions: 'storeQuote' } } },
    previewing: {
      on: {
        SIGN: { target: 'signed', actions: 'storeHash' },
        REJECT: { target: 'quote', actions: 'clear' }
      }
    },
    signed: { on: { BROADCAST: 'broadcasting' } },
    broadcasting: { on: { CONFIRMED: { target: 'confirmed', actions: 'storeBlock' } } },
    confirmed: { type: 'final' }
  }
});
```

