import { setup, assign } from 'xstate';

interface Ctx { set: number; totalSets: number; reps: number; targetReps: number }

type Ev =
  | { type: 'BEGIN' }
  | { type: 'REP' }
  | { type: 'FINISH_SET' }
  | { type: 'NEXT_SET' }
  | { type: 'END' };

export const workoutMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  delays: { REST_AFTER: 60000 },
  guards: {
    metTarget: ({ context }) => context.reps >= context.targetReps,
    moreSets: ({ context }) => context.set < context.totalSets
  }
}).createMachine({
  id: 'workout',
  context: { set: 1, totalSets: 4, reps: 0, targetReps: 10 },
  initial: 'resting',
  states: {
    resting: { on: { BEGIN: 'working' } },
    working: {
      on: {
        REP: { actions: assign({ reps: ({ context }) => context.reps + 1 }) },
        FINISH_SET: { target: 'restTimerAfter', guard: 'metTarget' }
      }
    },
    restTimerAfter: {
      after: { REST_AFTER: 'setComplete' },
      on: { NEXT_SET: 'setComplete' }
    },
    setComplete: {
      always: [
        { guard: 'moreSets', target: 'working', actions: assign({ set: ({ context }) => context.set + 1, reps: () => 0 }) }
      ],
      on: { END: 'done' }
    },
    done: { type: 'final' }
  }
});
