  id: 'emailVerify',
  context: { email: '', code: '', attempts: 0 },
  initial: 'idle',
  states: {
    idle: {
      on: { SEND: { target: 'sent', actions: assign({ email: ({ event }) => event.email, code: ({ event }) => event.code, attempts: () => 0 }) } }
    },
    sent: { always: 'waiting' },
    waiting: {
      after: { CODE_TTL: 'expired' },
      on: {
        ENTER: [
          { guard: 'codeMatches', target: 'verified' },
          { target: 'waiting', actions: assign({ attempts: ({ context }) => context.attempts + 1 }), reenter: false }
        ]
      }
    },
    verified: { type: 'final' },
    expired: {
      on: { RESEND: { target: 'idle', actions: assign({ code: () => '', attempts: () => 0 }) } }
    }
  }
