import { setup, assign } from 'xstate';

interface Ctx { version: string; replicas: number; ready: number; failures: number }

type Ev =
  | { type: 'DEPLOY'; version: string; replicas: number }
  | { type: 'POD_READY' }
  | { type: 'POD_FAIL' }
  | { type: 'ACK' };

export const rolloutMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  guards: {
    allReady: ({ context }) => context.ready >= context.replicas,
    tooManyFail: ({ context }) => context.failures >= 2
  }
}).createMachine({
  id: 'rollout',
  context: { version: '', replicas: 0, ready: 0, failures: 0 },
  initial: 'pending',
  states: {
    pending: {
      on: { DEPLOY: { target: 'rollingOut', actions: assign({ version: ({ event }) => event.version, replicas: ({ event }) => event.replicas, ready: () => 0, failures: () => 0 }) } }
    },
    rollingOut: {
      on: {
        POD_READY: [
          { guard: 'allReady', target: 'healthy', actions: assign({ ready: ({ context }) => context.ready + 1 }) },
          { actions: assign({ ready: ({ context }) => context.ready + 1 }) }
        ],
        POD_FAIL: [
          { guard: 'tooManyFail', target: 'rollback', actions: assign({ failures: ({ context }) => context.failures + 1 }) },
          { actions: assign({ failures: ({ context }) => context.failures + 1 }) }
        ]
      }
    },
    healthy: { type: 'final' },
    rollback: { on: { ACK: 'pending' } }
  }
});
```

