import { setup, assign } from 'xstate';

interface Entry { cmd: string; output: string }
interface Ctx { input: string; history: Entry[]; current: string }

type Ev =
  | { type: 'TYPE'; value: string }
  | { type: 'RUN' }
  | { type: 'RESULT'; output: string }
  | { type: 'CLEAR' }
  | { type: 'NEXT' };

export const terminalMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev }
}).createMachine({
  id: 'terminal',
  context: { input: '', history: [], current: '' },
  initial: 'input',
  states: {
    input: {
      on: {
        TYPE: { actions: assign({ input: ({ event }) => event.value }) },
        RUN: { target: 'executing', guard: ({ context }) => context.input.trim().length > 0, actions: assign({ current: ({ context }) => context.input }) },
        CLEAR: { actions: assign({ history: () => [], input: () => '' }) }
      }
    },
    executing: {
      on: { RESULT: { target: 'result', actions: assign({ history: ({ context, event }) => [...context.history, { cmd: context.current, output: event.output }], input: () => '' }) } }
    },
    result: { on: { NEXT: 'input', CLEAR: { target: 'input', actions: assign({ history: () => [] }) } } }
  }
});
