Use a compound state: `waiting` accepts JOIN and READY, `readyCheck` gates the transition with a named guard that every player has flipped ready.

```typescript
import { setup, assign } from 'xstate';

type Ev = { type: 'JOIN'; id: string } | { type: 'READY'; id: string } | { type: 'GO' };
interface Ctx { players: { id: string; ready: boolean }[] }

export const miniLobby = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  guards: { everyoneReady: ({ context }) => context.players.length > 0 && context.players.every(p => p.ready) }
}).createMachine({
  id: 'miniLobby',
  context: { players: [] },
  initial: 'waiting',
  states: {
    waiting: {
      on: {
        JOIN: { actions: assign({ players: ({ context, event }) => [...context.players, { id: event.id, ready: false }] }) },
        READY: { target: 'readyCheck', actions: assign({ players: ({ context, event }) => context.players.map(p => p.id === event.id ? { ...p, ready: true } : p) }) }
      }
    },
    readyCheck: { on: { GO: { target: 'live', guard: 'everyoneReady' } } },
    live: {}
  }
});
```

Use `after` with a named delay so `previewing` automatically transitions back to `quote` once the quote goes stale.

```typescript
