  context: { pair: '', price: 0 },
  initial: 'quote',
  states: {
    quote: { on: { QUOTE: { target: 'previewing', actions: assign({ pair: ({ event }) => event.pair, price: ({ event }) => event.price }) } } },
    previewing: { after: { QUOTE_TTL: 'quote' }, on: { SIGN: 'signed' } },
