Use a named guard that counts failures and pick it as the first transition for POD_FAIL; the unguarded fallback increments the counter without transitioning.

```typescript
import { setup, assign } from 'xstate';

interface Ctx { failures: number }
type Ev = { type: 'POD_FAIL' } | { type: 'ACK' };

export const rollbackGate = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  guards: { tooMany: ({ context }) => context.failures >= 3 }
}).createMachine({
  id: 'rollbackGate',
  context: { failures: 0 },
  initial: 'rolling',
  states: {
    rolling: {
      on: {
        POD_FAIL: [
          { guard: 'tooMany', target: 'rollback' },
          { actions: assign({ failures: ({ context }) => context.failures + 1 }) }
        ]
      }
    },
