  id: 'editLock',
  context: { submittedAt: null },
  initial: 'draft',
  states: {
    draft: {
      on: {
        ANSWER: {},
        SUBMIT: { target: 'submitted', actions: assign({ submittedAt: () => Date.now() }) }
      }
    },
