The `waiting` state holds the code and uses `after` to transition to `expired` once the TTL elapses. Resending from `expired` re-enters `sent` and cycles back through `waiting`, which restarts the timer naturally.

```typescript
import { setup, assign } from 'xstate';

interface Ctx { code: string }
type Ev = { type: 'SEND'; code: string } | { type: 'ENTER'; code: string } | { type: 'RESEND' };

export const verifyResendMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  delays: { TTL: 5 * 60 * 1000 },
  guards: { match: ({ context, event }) => event.type === 'ENTER' && event.code === context.code }
}).createMachine({
  id: 'verifyResend',
  context: { code: '' },
  initial: 'idle',
  states: {
    idle: { on: { SEND: { target: 'sent', actions: assign({ code: ({ event }) => event.code }) } } },
    sent: { always: 'waiting' },
    waiting: {
      after: { TTL: 'expired' },
      on: { ENTER: [ { guard: 'match', target: 'verified' } ] }
    },
    verified: { type: 'final' },
    expired: { on: { RESEND: 'idle' } }
  }
});
```

The machine counts ready pods and failures as it progresses. Each POD_READY bumps `ready`; when it reaches the target, we transition to `healthy`. Each POD_FAIL bumps `failures`; the first transition is guarded by a failure-budget check that jumps straight to `rollback`, and the fallback just records the failure.

```typescript
import { setup, assign } from 'xstate';

interface Ctx { target: number; ready: number; failures: number; budget: number }
type Ev = { type: 'START'; target: number } | { type: 'POD_READY' } | { type: 'POD_FAIL' };

export const budgetRollout = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  guards: {
    ok: ({ context }) => context.ready + 1 >= context.target,
    over: ({ context }) => context.failures + 1 > context.budget
  }
}).createMachine({
  id: 'budgetRollout',
  context: { target: 0, ready: 0, failures: 0, budget: 2 },
  initial: 'pending',
  states: {
    pending: { on: { START: { target: 'rollingOut', actions: assign({ target: ({ event }) => event.target, ready: () => 0, failures: () => 0 }) } } },
    rollingOut: {
      on: {
        POD_READY: [
          { guard: 'ok', target: 'healthy' },
          { actions: assign({ ready: ({ context }) => context.ready + 1 }) }
        ],
        POD_FAIL: [
          { guard: 'over', target: 'rollback' },
          { actions: assign({ failures: ({ context }) => context.failures + 1 }) }
        ]
      }
    },
    healthy: { type: 'final' },
    rollback: {}
  }
});
```

