import { setup, assign } from 'xstate';

interface Ctx { ready: number; target: number; lastPing: number }

type Ev =
  | { type: 'DEPLOY'; target: number }
  | { type: 'POD_READY' }
  | { type: 'PING'; at: number };

export const rolloutParallel = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  guards: { done: ({ context }) => context.ready + 1 >= context.target }
}).createMachine({
  id: 'rolloutParallel',
  context: { ready: 0, target: 0, lastPing: 0 },
  type: 'parallel',
  states: {
    progress: {
      initial: 'pending',
      states: {
        pending: { on: { DEPLOY: { target: 'rollingOut', actions: assign({ target: ({ event }) => event.target, ready: () => 0 }) } } },
        rollingOut: {
          on: {
            POD_READY: [
              { guard: 'done', target: 'healthy', actions: assign({ ready: ({ context }) => context.ready + 1 }) },
              { actions: assign({ ready: ({ context }) => context.ready + 1 }) }
            ]
          }
        },
        healthy: { type: 'final' }
      }
    },
    health: {
      initial: 'watching',
      states: {
        watching: { on: { PING: { actions: assign({ lastPing: ({ event }) => event.at }) } } }
      }
    }
  }
});
